"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

type VoiceState = "idle" | "listening" | "speaking";

interface VoiceButtonProps
  extends
    Omit<React.ComponentProps<"button">, "children">,
    VariantProps<typeof voiceButtonVariants> {
  /** Current voice state */
  state?: VoiceState;
  /** Volume level 0-1 for waveform animation */
  volumeLevel?: number;
  /** Called when user clicks to toggle */
  onStateToggle?: (currentState: VoiceState) => void;
  /** Custom label per state */
  labels?: Partial<Record<VoiceState, string>>;
}

// =============================================================================
// VARIANTS
// =============================================================================

const voiceButtonVariants = cva(
  "inline-flex items-center justify-center gap-2 rounded-full font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      size: {
        sm: "h-10 px-4 text-sm",
        md: "h-12 px-5 text-sm",
        lg: "h-14 px-6 text-base",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// MINI WAVEFORM
// =============================================================================

const BAR_COUNT = 5;

function MiniWaveform({
  volumeLevel = 0,
  state,
  className,
}: {
  volumeLevel: number;
  state: VoiceState;
  className?: string;
}) {
  const [bars, setBars] = React.useState<number[]>(() =>
    new Array(BAR_COUNT).fill(0.15)
  );

  React.useEffect(() => {
    if (state === "idle") {
      setBars(new Array(BAR_COUNT).fill(0.15));
      return;
    }

    let frame: number;
    let t = 0;

    const animate = () => {
      t += 0.08;
      const newBars = new Array(BAR_COUNT).fill(0).map((_, i) => {
        if (state === "listening") {
          const base = volumeLevel * 0.6;
          const wave = Math.sin(t * 2 + i * 0.8) * 0.2 * volumeLevel;
          return Math.max(0.1, Math.min(1, base + wave));
        }
        // speaking
        const base = volumeLevel * 0.7;
        const wave = Math.sin(t * 3 + i * 1.2) * 0.25 * volumeLevel;
        return Math.max(0.1, Math.min(1, base + wave));
      });
      setBars(newBars);
      frame = requestAnimationFrame(animate);
    };

    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [state, volumeLevel]);

  return (
    <div className={cn("flex items-center gap-0.5", className)}>
      {bars.map((h, i) => (
        <div
          key={i}
          className="w-0.5 rounded-full bg-current transition-[height] duration-75"
          style={{ height: `${h * 20}px` }}
        />
      ))}
    </div>
  );
}

// =============================================================================
// COMPONENT
// =============================================================================

const defaultLabels: Record<VoiceState, string> = {
  idle: "Start Listening",
  listening: "Listening...",
  speaking: "Speaking...",
};

function VoiceButton({
  state = "idle",
  volumeLevel = 0,
  onStateToggle,
  labels,
  size,
  className,
  ...props
}: VoiceButtonProps) {
  const resolvedSize = size ?? "md";
  const mergedLabels = { ...defaultLabels, ...labels };

  const handleClick = React.useCallback(() => {
    onStateToggle?.(state);
  }, [onStateToggle, state]);

  return (
    <button
      type="button"
      data-slot="voice-button"
      data-state={state}
      onClick={handleClick}
      className={cn(
        voiceButtonVariants({ size: resolvedSize }),
        state === "idle" &&
          "bg-primary text-primary-foreground hover:bg-primary/90",
        state === "listening" &&
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        state === "speaking" &&
          "bg-secondary text-secondary-foreground hover:bg-secondary/90",
        className
      )}
      aria-label={mergedLabels[state]}
      {...props}
    >
      {/* Mic icon for idle, waveform for active states */}
      {state === "idle" ? (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        >
          <rect x="5" y="1" width="6" height="9" rx="3" />
          <path d="M3.5 7.5a4.5 4.5 0 0 0 9 0" />
          <line x1="8" y1="12" x2="8" y2="15" />
          <line x1="5.5" y1="15" x2="10.5" y2="15" />
        </svg>
      ) : (
        <MiniWaveform volumeLevel={volumeLevel} state={state} />
      )}
      <span>{mergedLabels[state]}</span>
    </button>
  );
}

VoiceButton.displayName = "VoiceButton";

export { VoiceButton, voiceButtonVariants };
export type { VoiceButtonProps, VoiceState };
